#include <stdio.h>
#include <stdlib.h>
typedef struct Node {
    int value;
    int key;
    struct Node** children;
    int numChildren;
} Node;
Node* createNode(int value, int key) {
    Node* node = (Node*)malloc(sizeof(Node));
    node->value = value;
    node->key = key;
    node->children = NULL;
    node->numChildren = 0;
    return node;
}
void addChild(Node* node, Node* child) {
    node->numChildren++;
    node->children = (Node**)realloc(node->children, node->numChildren * sizeof(Node*));
    node->children[node->numChildren - 1] = child;
}
int dfs(Node* node) {
    int sum = node->value;
    for (int i = 0; i < node->numChildren; i++) {
        sum += dfs(node->children[i]);
    }
    return sum;
}
void updateValues(Node* node, int value) {
    node->value += value;
    for (int i = 0; i < node->numChildren; i++) {
        updateValues(node->children[i], value);
    }
}
void removeSubtree(Node* node) {
    for (int i = 0; i < node->numChildren; i++) {
        removeSubtree(node->children[i]);
    }
    free(node->children);
    free(node);
}
int main() {
    int N;
    scanf("%d", &N);
    Node** nodes = (Node**)malloc(N * sizeof(Node*));
    for (int i = 0; i < N; i++) {
        int value;
        scanf("%d", &value);
        nodes[i] = createNode(value, i);
    }
    for (int i = 0; i < N - 1; i++) {
        int u, v;
        scanf("%d %d", &u, &v);
        addChild(nodes[u], nodes[v]);
    }
    int M;
    scanf("%d", &M);
    int special = 0;
    for (int i = 0; i < M; i++) {
        int type;
        scanf("%d", &type);
        if (type == 1) {
            int key, value;
            scanf("%d %d", &key, &value);
            key += special;
            Node* newNode = createNode(value, N);
            addChild(nodes[key], newNode);
            N++;
        } else if (type == 2) {
            int key, value;
            scanf("%d %d", &key, &value);
            key += special;
            updateValues(nodes[key], value);
        } else if (type == 3) {
            int key;
            scanf("%d", &key);
            key += special;
            removeSubtree(nodes[key]);
        } else if (type == 4) {
            int key;
            scanf("%d", &key);
            key += special;
            special = dfs(nodes[key]);
            printf("%d\n", special);
        }
    }
    return 0;
}

