import java.util.ArrayList;
import java.util.Scanner;
public class Main {
    static class Node {
        int value;
        int key;
        ArrayList<Node> children;
        public Node(int value, int key) {
            this.value = value;
            this.key = key;
            this.children = new ArrayList<>();
        }
    }

    public static void addChild(Node node, Node child) {
        node.children.add(child);
    }

    public static int dfs(Node node) {
        int sum = node.value;
        for (Node child : node.children) {
            sum += dfs(child);
        }
        return sum;
    }

    public static void updateValues(Node node, int value) {
        node.value += value;
        for (Node child : node.children) {
            updateValues(child, value);
        }
    }

    public static void removeSubtree(Node node) {
        for (Node child : node.children) {
            removeSubtree(child);
        }
    }

    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        int N = scanner.nextInt();
        Node[] nodes = new Node[N];
        for (int i = 0; i < N; i++) {
            int value = scanner.nextInt();
            nodes[i] = new Node(value, i);
        }
        for (int i = 0; i < N - 1; i++) {
            int u = scanner.nextInt();
            int v = scanner.nextInt();
            addChild(nodes[u], nodes[v]);
        }
        int M = scanner.nextInt();
        int special = 0;
        for (int i = 0; i < M; i++) {
            int type = scanner.nextInt();
            if (type == 1) {
                int key = scanner.nextInt();
                int value = scanner.nextInt();
                key += special;
                Node newNode = new Node(value, N);
                addChild(nodes[key], newNode);
                N++;
            } else if (type == 2) {
                int key = scanner.nextInt();
                int value = scanner.nextInt();
                key += special;
                updateValues(nodes[key], value);
            } else if (type == 3) {
                int key = scanner.nextInt();
                key += special;
                removeSubtree(nodes[key]);
            } else if (type == 4) {
                int key = scanner.nextInt();
                key += special;
                special = dfs(nodes[key]);
                System.out.println(special);
            }
        }
    }
}

